    {
      "input": {
        "module": "0100000001060160017e017e071302066d656d6f727902000673717561726500000020007e0b"
      },
      "expected_output": "error=compile_failed\ndetail=Validation error: Bad magic number (at offset 0)\u0000\n"
    }
  ]
}

Here are the public test cases for feature2_function_invocation:
{
  "description": "Looking up an exported function by name and calling it; looking up a name that is not exported reports it as missing; calling with the wrong number or wrong type of arguments yields normalized argument errors.",
  "cases": [
    {
      "input": {
        "module": "0061736d0100000001060160017e017e030201000405017001010105030100020608017f01418088040b071302066d656d6f727902000673717561726500000a09010700200020007e0b",
        "build": true,
        "steps": [
          {
            "op": "invoke",
            "name": "square",
            "args": [
              1234
            ]
          },
          {
            "op": "lookup",
            "name": "not_a_function"
          }
        ]
      },
      "expected_output": "result[square]=1522756\nlookup[not_a_function]=missing\n"
    },
    {
      "input": {
        "module": "0061736d0100000001060160017e017e030201000405017001010105030100020608017f01418088040b071302066d656d6f727902000673717561726500000a09010700200020007e0b",
        "build": true,
        "steps": [
          {
            "op": "invoke",
            "name": "square",
            "args": []
          }
        ]
      },
      "expected_output": "error=argument_count\n"
    },
    {
      "input": {
        "module": "0061736d0100000001060160017e017e030201000405017001010105030100020608017f01418088040b071302066d656d6f727902000673717561726500000a09010700200020007e0b",
        "build": true,
        "steps": [
          {
            "op": "invoke",
            "name": "square",
            "args": [
              1.23
            ]
          }
        ]
      },
      "expected_output": "error=argument_type\n"
    }
  ]
}

