    }
  ]
}

Here are the public test cases for feature6_globals:
{
  "description": "Reading exported and imported globals, calling a function that depends on them, writing a mutable global and observing the dependent function change, then the errors raised by writing a constant global and by writing a value of the wrong type.",
  "cases": [
    {
      "input": {
        "module": "0061736d010000000105016000017f020c0103656e7603626172037f000302010004040170000005030100010606017f0141250b071603066d656d6f727902000362617a000003666f6f03010a09010700230123006c0b0b0a0100410c0b0425000000",
        "imports": [
          {
            "kind": "global",
            "module": "env",
            "name": "bar",
            "value": 10
          }
        ],
        "build": true,
        "steps": [
          {
            "op": "read_global",
            "name": "foo"
          },
          {
            "op": "read_import_global",
            "ref": "env::bar"
          },
          {
            "op": "invoke",
            "name": "baz",
            "args": []
          },
          {
            "op": "write_global",
            "name": "foo",
            "value": 99
          },
          {
            "op": "invoke",
            "name": "baz",
            "args": []
          },
          {
            "op": "write_import_global",
            "ref": "env::bar",
            "value": 100
          },
          {
            "op": "write_global",
            "name": "foo",
            "value": 3.14159
          }
        ]
      },
      "expected_output": "global[foo]=37\nglobal[env::bar]=10\nresult[baz]=370\nglobal[foo]=99\nresult[baz]=990\nerror=const_global_write\nerror=bad_value_type\ntype=int32\n"
    }
  ]
}

Here are the public test cases for feature7_1_memory_ops:
{
  "description": "Creating a standalone linear memory, reporting its size in pages and bytes, writing and reading a byte, growing it by some pages, and confirming size grew and the written byte survived the grow.",
  "cases": [
    {
      "input": {
        "module": "0061736d0100000006810000",
        "standalone_memory": {
          "pages": 100
        },
        "memory_ops": [
          {
            "op": "info"
          },
          {
            "op": "write",
            "index": 123,
            "value": 45
          },
          {
            "op": "read",
            "index": 123
          },
          {
            "op": "grow",
            "pages": 10
          },
          {
            "op": "info"
          },
          {
            "op": "read",
            "index": 123
          }
        ]
      },
      "expected_output": "pages=100\nbytes=6553600\nwrite[123]=45\nbyte[123]=45\ngrow[10]=ok\npages=110\nbytes=7208960\nbyte[123]=45\n"
    }
  ]
}

Here are the public test cases for feature7_2_memory_errors:
{
  "description": "Memory operations that exceed limits: requesting an impossibly large initial size fails creation; growing past the implementation limit fails; growing past a declared maximum fails. Each yields a normalized category.",
  "cases": [
    {
      "input": {
        "module": "0061736d0100000006810000",
        "standalone_memory": {
          "pages": 1000000000
        }
      },
      "expected_output": "error=memory_create_failed\n"
    },
    {
      "input": {
        "module": "0061736d0100000006810000",
        "standalone_memory": {
          "pages": 100,
          "max": 200
        },
        "memory_ops": [
          {
            "op": "grow",
            "pages": 300
          }
        ]
      },
      "expected_output": "error=memory_grow_failed\n"
    }
  ]
}

